import { cfg, withDb } from "./db.mjs";

function quoteIdent(value) {
  return `"${String(value).replaceAll('"', '""')}"`;
}

export async function ensureSchema(client) {
  await client.query(`CREATE SCHEMA IF NOT EXISTS ${quoteIdent(cfg.schema)}`);
  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id text PRIMARY KEY,
      doc jsonb NOT NULL,
      CONSTRAINT accounts_doc_is_object CHECK (jsonb_typeof(doc) = 'object'),
      CONSTRAINT accounts_doc_required_fields CHECK (
        doc ? 'accountId'
        AND doc ? 'name'
        AND doc ? 'tier'
        AND doc ? 'status'
        AND doc ? 'createdAt'
      ),
      CONSTRAINT accounts_doc_account_id_matches CHECK (doc->>'accountId' = account_id),
      CONSTRAINT accounts_doc_tier_check CHECK ((doc->>'tier') = ANY (ARRAY['strategic', 'midmarket', 'standard'])),
      CONSTRAINT accounts_doc_status_check CHECK ((doc->>'status') = ANY (ARRAY['active', 'at-risk', 'churned'])),
      CONSTRAINT accounts_doc_created_at_check CHECK (jsonb_typeof(doc->'createdAt') = 'string')
    )
  `);
  await client.query('CREATE INDEX IF NOT EXISTS accounts_doc_gin_idx ON accounts USING GIN (doc)');
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client))
    .then(() => console.log("schema ready"))
    .catch((e) => {
      console.error(e);
      process.exit(1);
    });
}

import { ensureSchema } from "./schema.mjs";

function nowIso() {
  return new Date().toISOString();
}

function toIsoDate(value) {
  if (value instanceof Date) {
    return value.toISOString();
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    throw new Error("Invalid createdAt");
  }
  return date.toISOString();
}

function normalizeAccountDoc(data, existing = {}) {
  const doc = {
    ...existing,
    ...data,
    accountId: existing.accountId ?? data.accountId,
    createdAt: existing.createdAt ? toIsoDate(existing.createdAt) : data.createdAt ? toIsoDate(data.createdAt) : nowIso(),
  };

  if (!doc.accountId) {
    throw new Error("accountId is required");
  }

  return doc;
}

function toJsonb(doc) {
  return JSON.stringify(doc);
}

export async function createAccounts(db, data) {
  await ensureSchema(db);
  const doc = normalizeAccountDoc(data);
  const result = await db.query(
    "INSERT INTO accounts (account_id, doc) VALUES ($1, $2::jsonb) RETURNING doc",
    [doc.accountId, toJsonb(doc)],
  );
  return result.rows[0].doc;
}

export async function getAccounts(db, id) {
  const result = await db.query("SELECT doc FROM accounts WHERE account_id = $1", [id]);
  return result.rows[0]?.doc ?? null;
}

export async function updateAccounts(db, id, data) {
  await ensureSchema(db);
  const current = await getAccounts(db, id);
  if (!current) {
    return null;
  }

  const doc = normalizeAccountDoc(data, current);
  const result = await db.query(
    "UPDATE accounts SET doc = $2::jsonb WHERE account_id = $1 RETURNING doc",
    [id, toJsonb(doc)],
  );
  return result.rows[0]?.doc ?? null;
}

export async function deleteAccounts(db, id) {
  await ensureSchema(db);
  const result = await db.query("DELETE FROM accounts WHERE account_id = $1", [id]);
  return result.rowCount > 0;
}

